219	/// display text. The reference decides row sharing on its *internal*
220	/// (UN-abbreviated) term widths, which are structurally invisible to a crate
221	/// consuming display text — a caller that knows them (e.g. an adapter sitting
222	/// on the term representation) can pass them here (BEHAVIOR.md §3f, round 10).
223	/// Every field is optional; an absent field (or an absent [`CellWidths`]
224	/// altogether) falls back to the display-text estimate, byte-identically to
225	/// the no-override path.
226	#[derive(Clone, Debug, Default, PartialEq, Eq)]
227	pub struct CellWidths {
228	    /// The cell's row **occupancy** `C` (columns it counts for in its
229	    /// siblings' trigger budgets and fill denominators). Display-text
230	    /// default: `flat` plus the recursive tuple/union surcharge
231	    /// ([`CellShape::rec_sur`]).
232	    pub occupancy: Option<i64>,
233	    /// The cell's own trigger-budget **bonus**. Display-text default: the
234	    /// largest `⌊elems/2⌋ + 2` over its top-level tuple/union args (4 for an
235	    /// arg with ≥ 9 elements) — applied only when the fact's LAST top-level
236	    /// argument is such a tuple/union (round-11 WIT probe), else 0.
237	    pub bonus: Option<i64>,
238	    /// The cell's **fill numerator** (its internal width in the proportional
239	    /// fill share once it wraps). Display-text default:
240	    /// `flat + rec_sur + #function-nodes`.
241	    pub fill_width: Option<i64>,
242	    /// The cell's effective **self width** in the wrap-trigger comparisons
243	    /// (both passes), replacing the display flat width. Lets a caller make a
244	    /// cell wrap (or keep fitting) on a width it computed itself — including
245	    /// a lone cell, which wraps iff this exceeds 87. The fill layer still
246	    /// lays out the display text.
247	    pub trigger_width: Option<i64>,
248	}
