421	/// Build the DOT [`Graph`] for a [`System`]: allocate ids in emission order (so id
422	/// order == file order), emit free (non-clustered) node statements at the top
423	/// level, then the `cluster_…` subgraph blocks (role records, grouped by cluster
424	/// label in first-appearance order), then edges, then the legend sink-block + its
425	/// invis edges. Header is inferred from roles (§4).
426	pub fn generate(sys: &System) -> Graph {
427	    let mut alloc = NodeIdAllocator::new();
428	    let mut resolved: Vec<Resolved> = Vec::with_capacity(sys.nodes.len());
429	
430	    // Free top-level node statements, in emission order.
431	    let mut free: Vec<Stmt> = Vec::new();
432	    // Clusters: label -> (color, record statements), with first-appearance order.
433	    let mut cluster_order: Vec<String> = Vec::new();
434	    let mut clusters: std::collections::HashMap<String, (String, Vec<Stmt>)> =
435	        std::collections::HashMap::new();
436	
437	    // Pass 1: allocate ids and build node statements in emission order. A clustered
438	    // record's statement is routed into its cluster bucket; everything else is free.
439	    for node in &sys.nodes {
440	        if let Some(spec) = node.record_spec() {
441	            let ids = alloc.record(spec.cell_count());
442	            let mut it = ids.ports.into_iter();
443	            let ports_prem: Vec<String> = (0..spec.premises.len()).map(|_| it.next().unwrap()).collect();
444	            let port_info = it.next().unwrap();
445	            let ports_concl: Vec<String> =
446	                (0..spec.conclusions.len()).map(|_| it.next().unwrap()).collect();
447	            let rec = build_record(&spec, &ports_prem, &port_info, &ports_concl);
448	            let stmt = Stmt::Node(Node::record(ids.node.clone(), rec));
449	            match &spec.cluster {
450	                Some(c) => {
451	                    let entry = clusters.entry(c.label.clone()).or_insert_with(|| {
452	                        cluster_order.push(c.label.clone());
453	                        (c.color.clone(), Vec::new())
454	                    });
455	                    entry.1.push(stmt);
456	                }
457	                None => free.push(stmt),
458	            }
459	            resolved.push(Resolved::Record { ports_prem, ports_concl, node: ids.node });
460	            continue;
461	        }
462	        let id = alloc.node();
463	        let stmt = match node {
464	            GraphNode::Knowledge { term, temporal } => {
465	                let label = format!("!KU( {} ) @ #{}", term, temporal);
466	                Stmt::Node(Node::ellipse(id.clone(), Ellipse::colored(label, "gray")))
467	            }
468	            GraphNode::Action { fact, temporal } => {
469	                let label = format!("{} @ #{}", fact, temporal);
470	                Stmt::Node(Node::ellipse(id.clone(), Ellipse::colored(label, "darkblue")))
471	            }
472	            GraphNode::Compressed { temporal, rule } => {
473	                let label = format!("#{} : {}", temporal, rule);
474	                Stmt::Node(Node::ellipse(id.clone(), Ellipse::new(label)))
475	            }
476	            GraphNode::Temporal { var } => {
477	                Stmt::Node(Node::ellipse(id.clone(), Ellipse::new(format!("#{}", var))))
478	            }
479	            GraphNode::OpenTarget { node_var, premise_index } => {
480	                Stmt::Node(Node::shaped(id.clone(), Shaped::invtrapezium(node_var, *premise_index)))
481	            }
482	            GraphNode::Shaped { label, shape, color } => Stmt::Node(Node::shaped(
483	                id.clone(),
484	                Shaped { label: label.clone(), shape: shape.clone(), color: color.clone() },
485	            )),
486	            GraphNode::Rule(_) | GraphNode::RawRule(_) => unreachable!("records handled above"),
487	        };
488	        free.push(stmt);
489	        resolved.push(Resolved::Node(id));
490	    }
491	
492	    // Assemble: free nodes, then clusters (first-appearance order), then edges.
493	    let mut g = Graph::new(Header::Simple);
494	    for s in free {
495	        g.push(s);
496	    }
497	    for label in &cluster_order {
498	        let (color, body) = clusters.remove(label).unwrap();
499	        g.push(Stmt::Cluster(Cluster { label: label.clone(), color, body }));
500	    }
501	
502	    // Pass 2: edges.
503	    for e in &sys.edges {
504	        let src = endpoint(&resolved, e.src);
505	        let dst = endpoint(&resolved, e.dst);
506	        g.push(Stmt::Edge(Edge { src, dst, attrs: e.style.attrs() }));
507	    }
508	
509	    // Pass 3: legend sink-block, then its invis edges (observed order).
510	    if let Some(html) = &sys.legend_html {
511	        if !html.is_empty() {
512	            let legend_id = alloc.node();
513	            let block = RankBlock {
514	                rank: "sink".into(),
515	                body: vec![Stmt::Node(Node::plain(legend_id.clone(), html.clone()))],
516	            };
517	            g.push(Stmt::RankBlock(block));
518	            for (from, ()) in &sys.legend_edges {
519	                let src = endpoint(&resolved, *from);
520	                g.push(Stmt::Edge(Edge {
521	                    src,
522	                    dst: EndPoint::node(legend_id.clone()),
523	                    attrs: EdgeStyle::Invis.attrs(),
524	                }));
525	            }
526	        }
527	    }
528	
529	    g.set_inferred_header();
530	    g
531	}
