14	fn split_top_pipes(s: &str) -> Vec<String> {
15	    let mut out = Vec::new();
16	    let mut cur = String::new();
17	    let mut depth = 0i32;
18	    let bytes: Vec<char> = s.chars().collect();
19	    let mut i = 0;
20	    while i < bytes.len() {
21	        let c = bytes[i];
22	        if c == '\\' && i + 1 < bytes.len() {
23	            cur.push(c);
24	            cur.push(bytes[i + 1]);
25	            i += 2;
26	            continue;
27	        }
28	        match c {
29	            '{' => { depth += 1; cur.push(c); }
30	            '}' => { depth -= 1; cur.push(c); }
31	            '|' if depth == 0 => { out.push(std::mem::take(&mut cur)); }
32	            _ => cur.push(c),
33	        }
34	        i += 1;
35	    }
36	    out.push(cur);
37	    out
38	}
