340	    }
341	}
342	
343	fn main() {
344	    let dir = std::env::var("GRAPHCLEAN_CORPUS").expect("set GRAPHCLEAN_CORPUS");
345	    let mut files: Vec<_> = std::fs::read_dir(&dir)
346	        .expect("read corpus dir")
347	        .filter_map(|e| e.ok())
348	        .map(|e| e.path())
349	        .filter(|p| p.extension().map(|x| x == "dot").unwrap_or(false))
350	        .collect();
351	    files.sort();
352	
353	    // cell/record cross-validation totals
354	    let mut all_pc = 0u64;
355	    let mut all_pc_ok = 0u64;
356	    let mut wrap = 0u64;
357	    let mut wrap_ok = 0u64;
358	    let mut info_cells = 0u64;
359	    let mut info_ok = 0u64;
360	    let mut records = 0u64;
361	    let mut records_ok = 0u64;
362	
363	    // whole-payload
364	    let mut payloads = 0u64;
365	    let mut payloads_exact = 0u64;
366	    let mut payloads_with_skips = 0u64;
367	    let mut payloads_exact_strict = 0u64; // exact AND no skipped record
368	
369	    // family aggregation
370	    // key: (family, abbreviated, is_info)
371	    let mut fam: BTreeMap<(&'static str, bool, bool), u64> = BTreeMap::new();
372	    // one witness per family key
373	    let mut fam_witness: BTreeMap<(&'static str, bool, bool), (String, String, String, usize)> = BTreeMap::new();
374	    let mut struct_artifacts = 0u64;
375	
376	    for path in &files {
377	        let dot = std::fs::read_to_string(path).unwrap();
378	        let aliases = legend_aliases(&dot);
379	        payloads += 1;
380	        let mut file_exact = true;
381	        let mut file_skipped = false;
382	
383	        // process each record label; reconstruct and compare to original
384	        for label in each_record_label(&dot) {
385	            let out = process_record(&label, &aliases);
386	            if !out.parsed {
387	                file_skipped = true;
388	                continue;
389	            }
390	            records += 1;
391	            info_cells += 1;
392	            if out.info_ok { info_ok += 1; }
393	            all_pc += out.all_pc;
394	            all_pc_ok += out.all_pc_ok;
395	            wrap += out.wrap;
396	            wrap_ok += out.wrap_ok;
397	            if out.rec_ok { records_ok += 1; }
398	
399	            if out.struct_artifact {
400	                struct_artifacts += 1;
401	                if std::env::var("DBG").is_ok() && struct_artifacts <= 3 {
402	                    let b = first_diff_byte(&out.rebuilt, &label);
403	                    eprintln!("--- struct_artifact @ diff byte {} ---", b);
404	                    let lo = b.saturating_sub(15);
405	                    eprintln!("ORIG: ...{}", &label[lo..(b+40).min(label.len())]);
406	                    eprintln!("REB : ...{}", &out.rebuilt[lo..(b+40).min(out.rebuilt.len())]);
407	                }
408	            }
409	            if out.rebuilt != label {
410	                file_exact = false;
411	            }
412	            for d in &out.diverges {
413	                *fam.entry((d.family, d.abbreviated, d.is_info)).or_insert(0) += 1;
414	                fam_witness.entry((d.family, d.abbreviated, d.is_info)).or_insert_with(|| {
415	                    (d.flat.clone(), d.got.clone(), d.raw.clone(), d.first_byte)
416	                });
417	            }
418	        }
419	        if file_skipped { payloads_with_skips += 1; }
420	        if file_exact { payloads_exact += 1; }
421	        if file_exact && !file_skipped { payloads_exact_strict += 1; }
422	    }
423	
424	    let pct = |a: u64, b: u64| if b == 0 { 0.0 } else { 100.0 * a as f64 / b as f64 };
425	    println!("=== ROUND-11 WHOLE-PAYLOAD CENSUS over {} files ===", files.len());
426	    println!("(a) ALL prem/concl cells byte-exact: {}/{} = {:.3}%", all_pc_ok, all_pc, pct(all_pc_ok, all_pc));
427	    println!("    wrapping prem/concl cells:        {}/{} = {:.3}%", wrap_ok, wrap, pct(wrap_ok, wrap));
428	    println!("    info cells:                       {}/{} = {:.3}%", info_ok, info_cells, pct(info_ok, info_cells));
429	    println!("(b) RECORDS all-cells-exact:          {}/{} = {:.3}%", records_ok, records, pct(records_ok, records));
430	    println!("(c) WHOLE-PAYLOAD byte-exact (lenient, ignore unparsed recs): {}/{} = {:.3}%", payloads_exact, payloads, pct(payloads_exact, payloads));
431	    println!("(c) WHOLE-PAYLOAD byte-exact (strict, unparsed rec => fail):  {}/{} = {:.3}%", payloads_exact_strict, payloads, pct(payloads_exact_strict, payloads));
432	    println!("    payloads with >=1 unparsed record: {}", payloads_with_skips);
433	    println!("    reconstruction struct-artifacts (rec_ok but rebuilt!=orig): {}", struct_artifacts);
434	    println!();
435	    println!("=== DIVERGENCE FAMILIES (cell-level, ranked) ===");
436	    let mut famv: Vec<_> = fam.iter().collect();
437	    famv.sort_by(|a, b| b.1.cmp(a.1));
438	    let show = |s: &str| -> String {
439	        let s = s.replace("&nbsp;", "·").replace("\\l", "|");
440	        truncate_chars(&s, 90)
441	    };
442	    for ((f, ab, info), n) in famv {
443	        let w = fam_witness.get(&(*f, *ab, *info)).unwrap();
444	        println!("{:>7} x  {}{}{}", n, f,
445	            if *ab { " [ABBREV]" } else { "" },
446	            if *info { " [INFO]" } else { " [PC]" });
447	        println!("           flat: {}", truncate_chars(&w.0, 74));
448	        println!("           first-diverge-byte: {}", w.3);
449	        println!("           HS : {}", show(&w.2));
450	        println!("           got: {}", show(&w.1));
451	    }
452	}
