1	//! Byte-exact DOT serializer for [`Graph`].
2	//!
3	//! Reproduces the exact bytes the tamarin web UI emits at
4	//! `interactive-graph-def` (see workspace/BEHAVIOR.md §2, §3). The emission is
5	//! driven by one structural rule: every block is
6	//! `OPEN "\n"` + (each inner line + `"\n"`) + `"\n}"`, i.e. one blank line before
7	//! the closing brace; the top-level digraph then gets a final `"\n"`.
8	
9	use crate::model::*;
10	
11	/// Serialize a graph to DOT text (byte-exact against captured payloads).
12	pub fn to_dot(g: &Graph) -> String {
13	    let mut lines: Vec<String> = header_lines(g.header);
14	    for s in &g.body {
15	        lines.push(render_stmt(s));
16	    }
17	    // Top-level digraph block, plus the trailing newline the server emits.
18	    let mut out = render_block("digraph \"G\" {", &lines);
19	    out.push('\n');
20	    out
21	}
22	
23	/// `OPEN\n` + `line\n`* + `\n}`  (no trailing newline; callers add it if needed).
24	/// A `line` may itself be multi-line (a nested block); the per-line `\n` after it
25	/// supplies the separator the parent owes it.
26	fn render_block(open: &str, lines: &[String]) -> String {
27	    let mut s = String::new();
28	    s.push_str(open);
29	    s.push('\n');
30	    for l in lines {
31	        s.push_str(l);
32	        s.push('\n');
33	    }
34	    s.push_str("\n}");
35	    s
36	}
37	
38	fn header_lines(h: Header) -> Vec<String> {
39	    let raw: &[&str] = match h {
40	        Header::Simple => &[
41	            "nodesep=\"0.3\";",
42	            "ranksep=\"0.3\";",
43	            "node[fontsize=\"8\",fontname=\"Helvetica\",width=\"0.3\",height=\"0.2\"];",
44	            "edge[fontsize=\"8\",fontname=\"Helvetica\"];",
45	        ],
46	        Header::Compact => &[
47	            "nodesep=\"0.8\";",
48	            "ranksep=\"0.8\";",
49	            "sep=\"4\";",
50	            "splines=\"true\";",
51	            "overlap=\"false\";",
52	            "pack=\"true\";",
53	            "packmode=\"cluster\";",
54	            "concentrate=\"true\";",
55	            "compound=\"true\";",
56	            "remincross=\"true\";",
57	            "mclimit=\"10\";",
58	            "nslimit=\"20\";",
59	            "nslimit1=\"20\";",
60	            "ordering=\"out\";",
61	            "rankdir=\"TB\";",
62	            "showboxes=\"false\";",
63	            "clusterrank=\"local\";",
64	            "node[fontsize=\"8\",fontname=\"Helvetica\",width=\"0.3\",height=\"0.2\",margin=\"0.05,0.05\",shape=\"ellipse\"];",
65	            "edge[fontsize=\"8\",fontname=\"Helvetica\",penwidth=\"1.5\",arrowsize=\"0.5\",color=\"black\",style=\"solid\",weight=\"8\"];",
66	        ],
67	    };
68	    raw.iter().map(|s| s.to_string()).collect()
69	}
70	
71	fn render_stmt(s: &Stmt) -> String {
72	    match s {
73	        Stmt::Node(n) => render_node(n),
74	        Stmt::Edge(e) => render_edge(e),
75	        Stmt::Cluster(c) => render_cluster(c),
76	        Stmt::RankBlock(b) => render_rankblock(b),
77	    }
78	}
79	
80	fn render_node(n: &Node) -> String {
81	    match &n.kind {
82	        NodeKind::Record(r) => {
83	            format!(
84	                "{}[shape=\"record\",label=\"{}\",fillcolor=\"{}\",style=\"filled\",fontcolor=\"{}\",role=\"{}\"];",
85	                n.id,
86	                render_record_label(r),
87	                r.fillcolor,
88	                r.fontcolor,
89	                r.role.0,
90	            )
91	        }
92	        NodeKind::Ellipse(e) => match &e.color {
93	            Some(c) => format!(
94	                "{}[label=\"{}\",shape=\"ellipse\",color=\"{}\"];",
95	                n.id, e.label, c
96	            ),
97	            None => format!("{}[label=\"{}\",shape=\"ellipse\"];", n.id, e.label),
98	        },
99	        NodeKind::Shaped(s) => match &s.color {
100	            Some(c) => format!(
101	                "{}[label=\"{}\",shape=\"{}\",color=\"{}\"];",
102	                n.id, s.label, s.shape, c
103	            ),
104	            None => format!("{}[label=\"{}\",shape=\"{}\"];", n.id, s.label, s.shape),
105	        },
106	        NodeKind::Plain { html } => {
107	            format!("{}[shape=\"plain\",label=<{}>];", n.id, html)
108	        }
109	    }
110	}
111	
112	/// `{{<p> t|<p> t}|{<p> t}|{<p> t|<p> t}}` — outer braces, groups joined by `|`,
113	/// each group `{cell|cell}`, each cell `<port> text`.
114	fn render_record_label(r: &Record) -> String {
115	    let mut s = String::from("{");
116	    let groups: Vec<String> = r
117	        .columns
118	        .iter()
119	        .map(|col| {
120	            let cells: Vec<String> = col
121	                .iter()
122	                .map(|c| format!("<{}> {}", c.port, c.text))
123	                .collect();
124	            format!("{{{}}}", cells.join("|"))
125	        })
126	        .collect();
127	    s.push_str(&groups.join("|"));
128	    s.push('}');
129	    s
130	}
131	
132	fn render_edge(e: &Edge) -> String {
133	    let mut s = render_endpoint(&e.src);
134	    s.push_str(" -> ");
135	    s.push_str(&render_endpoint(&e.dst));
136	    if !e.attrs.is_empty() {
137	        let attrs: Vec<String> = e
138	            .attrs
139	            .iter()
140	            .map(|(k, v)| format!("{}=\"{}\"", k, v))
141	            .collect();
142	        s.push('[');
143	        s.push_str(&attrs.join(","));
144	        s.push(']');
145	    }
146	    s.push(';');
147	    s
148	}
149	
150	fn render_endpoint(ep: &EndPoint) -> String {
151	    match &ep.port {
152	        Some(p) => format!("{}:{}", ep.node, p),
153	        None => ep.node.clone(),
154	    }
155	}
156	
157	fn render_cluster(c: &Cluster) -> String {
158	    let mut lines = vec![
159	        "nodesep=\"0.6\";".to_string(),
160	        "ranksep=\"0.6\";".to_string(),
161	        format!("label=\"{}\";", c.label),
162	        "style=\"filled\";".to_string(),
163	        format!("color=\"{}\";", c.color),
164	        "penwidth=\"2\";".to_string(),
165	        format!("fillcolor=\"{}\";", c.color),
166	        "overlap=\"false\";".to_string(),
167	        "sep=\"4\";".to_string(),
168	    ];
169	    for s in &c.body {
170	        lines.push(render_stmt(s));
171	    }
172	    let open = format!("subgraph \"cluster_{}\" {{", c.label);
173	    render_block(&open, &lines)
174	}
175	
176	fn render_rankblock(b: &RankBlock) -> String {
177	    let mut lines = vec![format!("rank=\"{}\";", b.rank)];
178	    for s in &b.body {
179	        lines.push(render_stmt(s));
180	    }
181	    render_block("{", &lines)
182	}
