149	pub fn system_to_dot_with(sys: &System, opts: &GraphOptions) -> String {
150	    // 1. Pre-render simplification.  Clone-for-render boundary: from here on the
151	    //    working copy is a `RenderSystem` (display-only, write-sealed) so it can
152	    //    never be fed back into the prover — the compress/simplify passes mutate
153	    //    it in ways that leave the `subst_system` stamps meaningless.
154	    let working = RenderSystem::from_prover(sys.clone());
155	    let working = if opts.compress { compress_system(working) } else { working };
156	    let working = simplify_system(opts.simplification_level, working);
157	    // 2. Build the GraphRepr.  `compute_basic_graph_repr` takes `&System`;
158	    //    `&RenderSystem` derefs to it.
159	    let mut repr = compute_basic_graph_repr(&working);
160	    if opts.clustering_similar_names {
161	        add_intelligent_cluster_using_similar_names(&mut repr);
162	    } else {
163	        add_cluster_by_role(&mut repr);
164	    }
165	    // 3. Compute abbreviations.
166	    let abbrevs: Abbreviations = if opts.abbreviate {
167	        compute_abbreviations(&repr, &AbbreviationOptions::default())
168	    } else {
169	        Abbreviations::new()
170	    };
171	    // 4. Emit DOT.
172	    let mut g = DotBuilder::new();
173	    // HS `dotSystemCompact` (Dot.hs:481-487) computes the node colour map from
174	    // the RAW system's nodes (`nodeColorMap (M.elems $ get sNodes se)`), NOT
175	    // the compressed/simplified `working` used for the graph. Mirror that: the
176	    // palette is sized by the whole rule set, so it must see every original
177	    // node.
178	    let color_map = build_node_color_map(&sys.nodes);
179	    // HS `dotGraphCompact` (Dot.hs:490-513, see line 503) switches the graph-level defaults to
180	    // `setDefaultAttributesIfCluster` when the repr has any clusters.
181	    g.preamble(!repr.clusters.is_empty());
182	    let abbrev_lookup = |t: &LNTerm| -> Option<LNTerm> {
183	        abbrevs.get(t).map(|(a, _)| a.clone())
184	    };
185	    // Precompute a node-id -> rule map so edge styling is O(1) per edge
186	    // instead of scanning `working.nodes` per edge.
187	    let node_map: HashMap<&LVar, &RuleACInst> =
188	        working.nodes.iter().map(|(id, ru)| (id, ru)).collect();
189	    // HS `hasOutgoingEdge graph v` (Dot.hs:277-279): a node has an outgoing edge
190	    // iff it is the conclusion-side source of some `SystemEdge` in the graph's
191	    // TOP-LEVEL edge set (`get grEdges repr`). Clustering removes a cluster's
192	    // internal edges from `grEdges` (GraphRepr.hs:126-129), so we mirror HS and
193	    // consult ONLY `repr.edges` (post-clustering), never a cluster's own edges.
194	    // Drives the compact-node label choice in `rule_node`.
195	    let has_outgoing: HashSet<&LVar> = repr.edges.iter()
196	        .filter_map(|e| match e {
197	            GEdge::System(src, _) => Some(&src.0),
198	            _ => None,
199	        })
200	        .collect();
201	    // HS gives every node a globally-fresh dot id via `cacheState dsNodes`
202	    // (Dot.hs:108-110), so a single system-node id `v` that is ALSO an
203	    // unsolved-action atom and/or the last-action atom is drawn as SEVERAL
204	    // distinct dot nodes (`n5` record + `n7` ellipse …). RS's semantic dot-id
205	    // scheme derives one id per `v` (`dot_node_id`), so those extra ellipses
206	    // would collide with the record on a single id — graphviz merges them (the
207	    // ellipse overwrites the record) and the parity gate's label-keyed node map
208	    // drops the record. Mirror HS: the SystemNode / MissingNode own the base id
209	    // (their record ports / bare id are what `sEdges` reference via
210	    // `conc_port_ref`/`prem_port_ref` = HS `dsConcs`/`dsPrems`), and a colliding
211	    // UnsolvedAction / LastAction ellipse (which HS never references by an
212	    // sEdge) gets a distinct suffixed id.
213	    //
214	    // `dsNodes[v]` (which HS `dotLessEdge` resolves each less-edge endpoint
215	    // through, Dot.hs:408-409) is the LAST dot node emitted at `v`. Emission
216	    // order is the free `repr.nodes` (System, UnsolvedAction, LastAction,
217	    // Missing per `compute_basic_graph_repr`) then each cluster's nodes — so we
218	    // walk that exact order, assigning ids and overwriting `ds_nodes` as we go.
219	    //
220	    // `port_owner_ids` = the `v`s whose base id backs an sEdge port ref
221	    // (SystemNode records + MissingNodes). An UnsolvedAction/LastAction at such
222	    // a `v` MUST yield the base to that owner regardless of emission order (a
223	    // SystemNode can be clustered and thus emitted AFTER a free action ellipse).
224	    let port_owner_ids: HashSet<&LVar> = repr.nodes.iter()
225	        .chain(repr.clusters.iter().flat_map(|c| c.nodes.iter()))
226	        .filter(|n| matches!(n.ty, NodeType::System(_) | NodeType::Missing(_)))
227	        .map(|n| &n.id)
228	        .collect();
229	    let mut used_dot_ids: HashSet<String> = HashSet::new();
230	    // Assigned id for each UnsolvedAction (tag 0) / LastAction (tag 1) node,
231	    // keyed by (node id, tag) — at most one of each kind per `v`.
232	    let mut ellipse_dot_ids: std::collections::BTreeMap<(LVar, u8), String> =
233	        std::collections::BTreeMap::new();
234	    // `dsNodes`: v -> dot id of the LAST node emitted at v (less-edge target).
235	    let mut ds_nodes: std::collections::BTreeMap<LVar, String> =
236	        std::collections::BTreeMap::new();
237	    for node in repr.nodes.iter()
238	        .chain(repr.clusters.iter().flat_map(|c| c.nodes.iter()))
239	    {
240	        let base = DotBuilder::dot_node_id(&node.id);
241	        let id = match &node.ty {
242	            // Base-id owners: their id is referenced by sEdge port refs.
243	            NodeType::System(_) | NodeType::Missing(_) => {
244	                used_dot_ids.insert(base.clone());
245	                base
246	            }
247	            NodeType::UnsolvedAction(_) | NodeType::LastAction => {
248	                let tag: u8 = if matches!(node.ty, NodeType::LastAction) { 1 } else { 0 };
249	                let suffix = if tag == 1 { "__lastatom" } else { "__actionatom" };
250	                let id = if port_owner_ids.contains(&node.id)
251	                    || used_dot_ids.contains(&base)
252	                {
253	                    let mut cand = format!("{base}{suffix}");
254	                    let mut n = 2u32;
255	                    while used_dot_ids.contains(&cand) {
256	                        cand = format!("{base}{suffix}{n}");
257	                        n += 1;
258	                    }
259	                    cand
260	                } else {
261	                    base
262	                };
263	                used_dot_ids.insert(id.clone());
264	                ellipse_dot_ids.insert((node.id.clone(), tag), id.clone());
265	                id
266	            }
267	        };
268	        ds_nodes.insert(node.id.clone(), id);
269	    }
270	    // 4a. Top-level (ungrouped) nodes.
271	    //
272	    // HS `dotGraphCompact` (Dot.hs:505-510) emits, in order: the FREE
273	    // (ungrouped) nodes (`mapM_ dotNodeCompact nodes`), THEN the clusters
274	    // (`mapM_ dotCluster clusters`), THEN the edges.  The free nodes — e.g. an
275	    // unsolved-action-atom ellipse like `Unlock_0(..) @ #t2.1` — therefore
276	    // appear BEFORE any `subgraph cluster_*` block.  Emit them first to match
277	    // (a free node emitted after the cluster's closing `}` lands in the wrong
278	    // scope order vs HS).

